import dspy
from typing import Any

class SafetyGate(dspy.Module):
    def __init__(self, downstream_module):
        super().__init__()
        self.downstream = downstream_module
        self.safety_check = dspy.ChainOfThought('input,output -> verdict')

    def forward(self, **kwargs):
        raw_output = self.downstream(**kwargs)

        safety_input = f"input: {kwargs.get('input', '')}\noutput: {raw_output}"
        verdict = self.safety_check(input=safety_input)

        if 'unsafe' in verdict.verdict.lower():
            return dspy.Prediction(output="[REJECTED: Safety violation detected]", safe=False)

        return raw_output

class SafetyEnsemble(dspy.Module):
    def __init__(self, main_module):
        super().__init__()
        self.content_filter = dspy.ChainOfThought("text -> safety_rating")
        self.intent_detector = dspy.ChainOfThought("query -> intent")
        self.jailbreak_detector = dspy.ChainOfThought("prompt -> threat_level")
        self.main_module = main_module

    def forward(self, **kwargs):
        input_text = kwargs.get('input', '')

        safety_rating = self.content_filter(text=input_text)
        intent = self.intent_detector(query=input_text)
        threat_level = self.jailbreak_detector(prompt=input_text)

        safety_score = (0.4 * float(safety_rating.safety_rating or 0) +
                       0.3 * (1 if 'benign' in intent.intent else 0) +
                       0.3 * (1 if threat_level.threat_level in ['low', 'none'] else 0))

        if safety_score < 0.7:
            return dspy.Prediction(
                output="[BLOCKED: Insufficient safety score]",
                safety_score=safety_score
            )

        return self.main_module(**kwargs)

